import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';

function Header() {
  const [activeDropdown, setActiveDropdown] = useState(null); // 'women' | 'men' | 'accessories' | null
  const headerRef = useRef(null);

  const toggleDropdown = (name) => {
    setActiveDropdown((prev) => (prev === name ? null : name));
  };

  const closeDropdown = () => setActiveDropdown(null);

  useEffect(() => {
    // Close on outside click
    const onClick = (e) => {
      if (!headerRef.current) return;
      if (!headerRef.current.contains(e.target)) {
        closeDropdown();
      }
    };

    // Close on ESC
    const onKey = (e) => {
      if (e.key === 'Escape') closeDropdown();
    };

    document.addEventListener('mousedown', onClick);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', onClick);
      document.removeEventListener('keydown', onKey);
    };
  }, []);

  return (
    <header className="main-header" ref={headerRef}>
      <div className="top-row">
        <div className="title">AURELIA</div>
        <div className="search" role="button" aria-label="Search">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <circle cx="11" cy="11" r="7"></circle>
            <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
          </svg>
        </div>
        <div className="cart" role="button" aria-label="Cart">
          <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <path d="M3 3h2l2.5 12.5a1 1 0 0 0 .98.75h9.04a1 1 0 0 0 .98-.78L21 7H6" />
            <circle cx="10" cy="19" r="1.2" />
            <circle cx="18" cy="19" r="1.2" />
          </svg>
        </div>
      </div>

      <div className="bottom-row">
        <div className="nav-item">
          <button
            className="nav-link"
            aria-haspopup="true"
            aria-expanded={activeDropdown === 'women'}
            onClick={() => toggleDropdown('women')}
          >
            WOMEN
          </button>

          {activeDropdown === 'women' && (
            <ul className="dropdown-menu left">
              <li><Link className="dropdown-item" to="/women/fall" onClick={closeDropdown}>Fall Collection '25</Link></li>
              <li><Link className="dropdown-item" to="/women/spring" onClick={closeDropdown}>Spring Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/women/summer" onClick={closeDropdown}>Summer Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/women" onClick={closeDropdown}>View All</Link></li>
            </ul>
          )}
        </div>

        <div className="nav-item">
          <button
            className="nav-link"
            aria-haspopup="true"
            aria-expanded={activeDropdown === 'men'}
            onClick={() => toggleDropdown('men')}
          >
            MEN
          </button>

          {activeDropdown === 'men' && (
            <ul className="dropdown-menu center">
              <li><Link className="dropdown-item" to="/men/fall" onClick={closeDropdown}>Fall Collection '25</Link></li>
              <li><Link className="dropdown-item" to="/men/spring" onClick={closeDropdown}>Spring Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/men/summer" onClick={closeDropdown}>Summer Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/men" onClick={closeDropdown}>View All</Link></li>
            </ul>
          )}
        </div>

        <div className="nav-item">
          <button
            className="nav-link"
            aria-haspopup="true"
            aria-expanded={activeDropdown === 'accessories'}
            onClick={() => toggleDropdown('accessories')}
          >
            ACCESSORIES
          </button>

          {activeDropdown === 'accessories' && (
            <ul className="dropdown-menu right">
              <li><Link className="dropdown-item" to="/accessories/fall" onClick={closeDropdown}>Fall Collection '25</Link></li>
              <li><Link className="dropdown-item" to="/accessories/spring" onClick={closeDropdown}>Spring Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/accessories/summer" onClick={closeDropdown}>Summer Collection '26</Link></li>
              <li><Link className="dropdown-item" to="/accessories" onClick={closeDropdown}>View All</Link></li>
            </ul>
          )}
        </div>
      </div>
    </header>
  );
}

export default Header;
